// Recall / 決策 (MOCK LLM). The core value: answer "食乜 / 呢間叫乜" using the
// catalogue + memory. It runs ONLY on the few memories RAG hands it (never the
// whole store), and cites each with a timestamp ("X 前印象"). Templated in mock
// mode — NO LLM call; the real seam sends (query + retrieved) to an LLM.
//
// 唔老作 (hard product rule, §4b): when RAG has no CONFIDENT relevant memory, we
// say so honestly — never surface a weak match pretending to know. Fabricating
// on an unrelated query destroys trust. (The confidence threshold value is a
// coarse mock number; real embeddings will tune it. The behaviour is what must
// exist now.)

import type { Catalogue, Memory, Retrieved } from "./types";
import { retrieve, topTasteTags } from "./rag";
import { areaInQuery } from "./catalogue";
import { ago } from "./dom";

export const RECALL_MODE: "mock" | "real" = "mock";

// Coarse mock confidence bar. A genuine name/tag match scores well above this;
// an incidental single-character overlap ("好", "食") scores well below.
const CONFIDENT_MIN = 0.3;

// Recognised taste / cuisine words. Query words here that NO memory carries →
// honest "未有記錄" rather than a pivot.
const TASTE_VOCAB = [
  "辣", "甜", "鹹", "酸", "咖啡", "日式", "西式", "港式", "茶餐廳", "點心",
  "麵", "飯", "拉麵", "米線", "燒味", "海鮮", "炸", "快餐", "廣東", "甜品", "鑊氣",
  "壽司", "刺身", "放題", "泰", "泰國", "韓", "韓國", "越南", "印度", "素",
  "火鍋", "打邊爐", "燒烤", "牛扒", "扒", "意粉", "薄餅", "漢堡", "越", "台",
];

const RECOMMEND_RE = /食乜|食咩|食邊|推薦|介紹|今晚|唔知食|邊度食|想食|好唔好食|有咩好/;

// Strip generic suffixes so we match a place on its DISTINCTIVE part (brand),
// never on "餐廳 / 點心 / 專門店" which many places share (would mis-recall).
function distinctive(name: string): string {
  return name
    .replace(
      /(茶餐廳|餐廳|冰室|茶室|專門店|美食|飯店|酒家|酒樓|茶樓|快餐店|有限公司|分店|燒臘|點心)/g,
      ""
    )
    .trim();
}

export interface RecallResult {
  text: string;
  cited: Retrieved[];
  kind: "restaurant" | "recommend" | "general" | "empty";
}

function tagsInQuery(q: string): string[] {
  const found = [...new Set(TASTE_VOCAB.filter((t) => q.includes(t)))];
  // Drop a tag if a longer found tag contains it (keep 韓國, drop 韓).
  return found.filter((t) => !found.some((o) => o !== t && o.includes(t)));
}

// Did the user name a restaurant we actually remember? Match on the distinctive
// part only, ≥2 chars.
function mentionedRestaurant(query: string, memories: Memory[]): string | null {
  for (const m of memories) {
    const dn = distinctive(m.restaurantName);
    for (let i = 0; i + 2 <= dn.length; i++) {
      if (query.includes(dn.slice(i, i + 2))) return m.restaurantId;
    }
  }
  return null;
}

function dishList(cited: Retrieved[]): string {
  const names = new Set<string>();
  for (const r of cited) for (const d of r.memory.dishes) names.add(d.name);
  return [...names].slice(0, 4).join("、");
}

// Summarise per-dish 👍/👎 across the cited memories + suggest ordering the good
// one and avoiding the bad. "" when no dish carries a rating.
function ratingVerdict(cited: Retrieved[]): string {
  const good: string[] = [];
  const goodNames: string[] = [];
  const bad: string[] = [];
  const seen = new Set<string>();
  for (const c of cited)
    for (const d of c.memory.dishes) {
      if (seen.has(d.name) || !d.rating) continue;
      const why = d.reasons?.length ? `（${d.reasons.join("、")}）` : "";
      if (d.rating === "good") { good.push(d.name + why); goodNames.push(d.name); seen.add(d.name); }
      else if (d.rating === "bad") { bad.push(d.name + why); seen.add(d.name); }
    }
  const parts: string[] = [];
  if (good.length) parts.push(`👍 好食：${good.join("、")}`);
  if (bad.length) parts.push(`👎 唔好食：${bad.join("、")}`);
  if (!parts.length) return "";
  return " " + parts.join("；") + "。" + (goodNames.length ? `叫返${goodNames[0]}啦。` : "");
}

function honest(memories: Memory[], what?: string): RecallResult {
  const lead = what
    ? `我未有你${what}方面嘅記錄。`
    : "我未有你呢方面嘅記錄。";
  const tail =
    memories.length === 0
      ? "掃你嘅相簿，我就即刻記得返你去過邊、食過乜。"
      : "影多幾張俾我，或者問返你食過嘅嘢，我就答到。";
  return { kind: "empty", cited: [], text: lead + tail };
}

// Area-scoped question with no personal memory there → don't just dismiss;
// surface FEHD facts for the district (public data, clearly labelled, no quality
// claims — 唔老作). Zero-spend: deterministic, no LLM.
function areaFallback(cat: Catalogue, hit: { area: string; name: string }): RecallResult {
  let rl = 0, rr = 0, mr = 0, total = 0;
  for (const r of cat.restaurants) {
    if (r.area !== hit.area) continue;
    total += 1;
    if (r.type === "RL") rl += 1;
    else if (r.type === "RR") rr += 1;
    else if (r.type === "MR") mr += 1;
  }
  if (total === 0) return honest([]);
  const parts: string[] = [];
  if (rl) parts.push(`${rl.toLocaleString()} 間食肆`);
  if (rr) parts.push(`${rr.toLocaleString()} 間小食店`);
  if (mr) parts.push(`${mr} 間海鮮舫`);
  return {
    kind: "empty",
    cited: [],
    text:
      `你喺「${hit.name}」呢頭仲未有記錄。` +
      `不過（FEHD 資料）呢區有 ${total.toLocaleString()} 間持牌餐廳：${parts.join("、")}。` +
      `去「餐廳目錄」揀間試吓，食完影相記低，我下次就幫到你。`,
  };
}

export function answerRecall(
  query: string,
  memories: Memory[],
  cat: Catalogue
): RecallResult {
  const q = query.trim();
  const areaHit = areaInQuery(q);

  // No memories at all → area-aware FEHD fallback (頂住) instead of a flat brush-off.
  if (memories.length === 0) return areaHit ? areaFallback(cat, areaHit) : honest(memories);

  const tags = tagsInQuery(q);
  const restaurantId = mentionedRestaurant(q, memories);
  const cited = retrieve(q, memories, { restaurantId: restaurantId ?? undefined, tags });
  const bestRel = cited[0]?.relevance ?? 0;

  // 1) Named a restaurant we remember → recall it (confident by construction).
  if (restaurantId && cited.length) {
    const top = cited[0];
    const dishes = dishList(cited.slice(0, 2));
    const visits = cited.filter((c) => c.memory.restaurantId === top.memory.restaurantId);
    return {
      kind: "restaurant",
      cited,
      text:
        `你${ago(top.memory.ts)}去「${top.memory.restaurantName}」，` +
        `叫過${dishes ? "：" + dishes : "嘢食"}。` +
        (visits.length > 1 ? `（你去過 ${visits.length} 次）` : "") +
        ratingVerdict(visits) +
        (top.memory.confidence < 0.75 ? "（餐點係大概印象，去到再對一對）" : ""),
    };
  }

  // Area-scoped question but nothing logged in that district → FEHD area facts,
  // rather than recommending an unrelated district's memory.
  if (areaHit && !memories.some((m) => m.area === areaHit.area)) {
    return areaFallback(cat, areaHit);
  }

  // 2) Query names a specific taste/cuisine → only answer if a memory HAS it.
  if (tags.length) {
    const matched = cited.filter((c) =>
      c.memory.tasteTags.some((t) => tags.includes(t))
    );
    if (matched.length) {
      const pick = matched[0];
      return {
        kind: "recommend",
        cited: matched,
        text:
          `你成日鍾意${tags.join("、")}。${ago(pick.memory.ts)}你喺` +
          `「${pick.memory.restaurantName}」食過${pick.memory.dishes[0]?.name ?? "嘢食"}，` +
          `幾啱你口味 — 再去一次都唔錯。`,
      };
    }
    // 唔老作: we have NO record of this taste/cuisine.
    return honest(memories, `食「${tags.join("、")}」`);
  }

  // 3) Generic recommendation (no specific cuisine) → honest dominant-taste rec.
  if (RECOMMEND_RE.test(q)) {
    const flavour = topTasteTags(memories, 3);
    const pool = retrieve(flavour.join(" "), memories, { tags: flavour });
    const pick = pool[0] ?? cited[0] ?? { memory: memories[0], score: 0, relevance: 0 };
    return {
      kind: "recommend",
      cited: pool.length ? pool.slice(0, 3) : [pick],
      text:
        `你成日鍾意食${flavour.join("、")}。${ago(pick.memory.ts)}你喺` +
        `「${pick.memory.restaurantName}」食過${pick.memory.dishes[0]?.name ?? "嘢食"}，` +
        `幾啱你口味 — 再去一次，或者揀返類似嘅。`,
    };
  }

  // 4) Factual recall / general — require CONFIDENCE, else 唔老作.
  if (cited.length && bestRel >= CONFIDENT_MIN) {
    const lines = cited
      .slice(0, 3)
      .map(
        (c) =>
          `・${c.memory.restaurantName}（${ago(c.memory.ts)}）：` +
          c.memory.dishes.map((d) => d.name).join("、")
      )
      .join("\n");
    return { kind: "general", cited: cited.slice(0, 3), text: `根據你嘅飲食記憶：\n${lines}` };
  }

  return areaHit ? areaFallback(cat, areaHit) : honest(memories);
}
